using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalWordCount { get; set; }

    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "the","is","at","which","on","a","an","and","or","but",
        "in","with","to","for","of","it","this","that","was","are",
        "be","has","had","have","from","by","as","its","were","been"
    ];

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Sentence: s, Index: i, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string[] sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = ExtractWords(sentence);
        if (words.Length == 0) return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out var freq))
                score += freq;
        }
        // Normalize by word count to avoid bias toward long sentences
        return score / words.Length;
    }

    private static string[] ExtractWords(string text) =>
        WordRegex().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = request.DocumentText.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length,
            SummaryWordCount = summary.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length
        });
    }
}

